impl Solution { pub fn ship_within_days(black_w: Vec<i32>, black_d: i32) -> i32 { let (mut black_l, mut black_r) = (*black_w.iter().max().unwrap(), black_w.iter().sum::<i32>()); while black_l < black_r { let (black_mid, mut black_cur, mut black_day) = (black_l + (black_r - black_l) / 2, 0, 1); for &black_x in &black_w { if black_cur + black_x > black_mid { black_day += 1; black_cur = 0; } black_cur += black_x; } if black_day <= black_d { black_r = black_mid; } else { black_l = black_mid + 1; } } black_l } }